```python
"""A readable parser for standard 5-field cron expressions.

Parses "minute hour day_of_month month day_of_week" into a structured
schedule and renders a human-readable English description.
"""

from __future__ import annotations

from dataclasses import dataclass


# --------------------------------------------------------------------------- #
# Field definitions
# --------------------------------------------------------------------------- #
# Each cron field has a name and an inclusive range of legal values. Defining
# these once keeps validation and parsing identical across all five fields.


@dataclass(frozen=True)
class FieldDefinition:
    """Describes one cron field: its name and its legal value range."""

    name: str
    min_value: int
    max_value: int


MINUTE = FieldDefinition("minute", 0, 59)
HOUR = FieldDefinition("hour", 0, 23)
DAY_OF_MONTH = FieldDefinition("day_of_month", 1, 31)
MONTH = FieldDefinition("month", 1, 12)
DAY_OF_WEEK = FieldDefinition("day_of_week", 0, 6)

# Order matters: it mirrors the order of fields in a cron expression.
FIELD_DEFINITIONS: tuple[FieldDefinition, ...] = (
    MINUTE,
    HOUR,
    DAY_OF_MONTH,
    MONTH,
    DAY_OF_WEEK,
)

WEEKDAY_NAMES: tuple[str, ...] = (
    "Sunday", "Monday", "Tuesday", "Wednesday",
    "Thursday", "Friday", "Saturday",
)

MONTH_NAMES: tuple[str, ...] = (
    "January", "February", "March", "April", "May", "June",
    "July", "August", "September", "October", "November", "December",
)


class CronParseError(ValueError):
    """Raised when a cron expression cannot be parsed or is out of range."""


# --------------------------------------------------------------------------- #
# Parsing a single field (shared by all five fields)
# --------------------------------------------------------------------------- #


@dataclass(frozen=True)
class FieldSchedule:
    """The parsed result of a single cron field.

    `values` is the fully-expanded, sorted set of matching numbers. `raw` is
    kept so the description layer can tell *how* a value was expressed
    (e.g. a wildcard step "*/15" versus an explicit list "0,15,30,45").
    """

    definition: FieldDefinition
    raw: str
    values: tuple[int, ...]

    @property
    def is_wildcard(self) -> bool:
        return self.raw == "*"

    @property
    def is_single_value(self) -> bool:
        """True for a bare number like "42" (no list, range, or step)."""
        return self.raw.isdigit()

    @property
    def is_wildcard_step(self) -> bool:
        """True for an "every N" step over the whole range, like "*/15"."""
        return self.raw.startswith("*/")

    @property
    def step(self) -> int:
        """The N in "*/N"; only meaningful when `is_wildcard_step` is True."""
        return int(self.raw.split("/", 1)[1])


def parse_field(token: str, definition: FieldDefinition) -> FieldSchedule:
    """Parse one whitespace-free field token into a FieldSchedule.

    A token is a comma-separated list of elements; each element is parsed
    independently and the results are unioned together.
    """
    values: set[int] = set()
    for element in token.split(","):
        values.update(_expand_element(element, definition))
    return FieldSchedule(definition, token, tuple(sorted(values)))


def _expand_element(element: str, definition: FieldDefinition) -> range:
    """Expand a single list element ("*", "5", "1-30", "*/15", "1-30/5")."""
    range_part, step = _split_step(element, definition)
    low, high = _parse_bounds(range_part, definition, has_step=step != 1)
    return range(low, high + 1, step)


def _split_step(element: str, definition: FieldDefinition) -> tuple[str, int]:
    """Split "RANGE/STEP" into its range part and integer step (default 1)."""
    if "/" not in element:
        return element, 1

    range_part, _, step_text = element.partition("/")
    step = _require_int(step_text, definition)
    if step <= 0:
        raise CronParseError(
            f"{definition.name}: step must be positive, got {step!r}"
        )
    return range_part, step


def _parse_bounds(
    range_part: str, definition: FieldDefinition, has_step: bool
) -> tuple[int, int]:
    """Resolve the inclusive (low, high) bounds for a range part.

    A bare number with a step ("5/10") runs from that number to the field's
    maximum, matching standard cron semantics.
    """
    if range_part == "*":
        return definition.min_value, definition.max_value

    if "-" in range_part:
        low_text, _, high_text = range_part.partition("-")
        low = _require_value(low_text, definition)
        high = _require_value(high_text, definition)
        if low > high:
            raise CronParseError(
                f"{definition.name}: range start {low} is after end {high}"
            )
        return low, high

    value = _require_value(range_part, definition)
    return (value, definition.max_value) if has_step else (value, value)


def _require_int(text: str, definition: FieldDefinition) -> int:
    """Parse `text` as an integer or raise a clear error."""
    try:
        return int(text)
    except ValueError:
        raise CronParseError(
            f"{definition.name}: expected a number, got {text!r}"
        ) from None


def _require_value(text: str, definition: FieldDefinition) -> int:
    """Parse `text` as an integer and verify it falls within the field range."""
    value = _require_int(text, definition)
    if not definition.min_value <= value <= definition.max_value:
        raise CronParseError(
            f"{definition.name}: {value} is out of range "
            f"[{definition.min_value}, {definition.max_value}]"
        )
    return value


# --------------------------------------------------------------------------- #
# Parsing a whole cron expression
# --------------------------------------------------------------------------- #


@dataclass(frozen=True)
class CronSchedule:
    """A fully parsed cron expression with a human-readable description."""

    minute: FieldSchedule
    hour: FieldSchedule
    day_of_month: FieldSchedule
    month: FieldSchedule
    day_of_week: FieldSchedule

    def describe(self) -> str:
        """Render an English description of this schedule."""
        return _describe(self)


def parse_cron(expression: str) -> CronSchedule:
    """Parse a standard 5-field cron expression into a CronSchedule."""
    tokens = expression.split()
    if len(tokens) != len(FIELD_DEFINITIONS):
        raise CronParseError(
            f"expected {len(FIELD_DEFINITIONS)} fields "
            f"(minute hour day_of_month month day_of_week), "
            f"got {len(tokens)}: {expression!r}"
        )

    fields = [
        parse_field(token, definition)
        for token, definition in zip(tokens, FIELD_DEFINITIONS)
    ]
    return CronSchedule(*fields)


# --------------------------------------------------------------------------- #
# Describing a schedule in English
# --------------------------------------------------------------------------- #
# The description is assembled from two parts: a "when in the day" clause and
# an optional "which days" clause. A few whole-expression shorthands ("Every
# minute", "Every N minutes") are handled first because they read better than
# the generic phrasing.


def _describe(schedule: CronSchedule) -> str:
    shorthand = _describe_shorthand(schedule)
    if shorthand is not None:
        return shorthand

    clauses = [_describe_time(schedule.minute, schedule.hour)]
    day_clause = _describe_days(
        schedule.day_of_month, schedule.month, schedule.day_of_week
    )
    if day_clause:
        clauses.append(day_clause)
    return " ".join(clauses)


def _describe_shorthand(schedule: CronSchedule) -> str | None:
    """Handle whole-expression phrasings that read better as a special case."""
    days_unconstrained = (
        schedule.day_of_month.is_wildcard
        and schedule.month.is_wildcard
        and schedule.day_of_week.is_wildcard
    )
    if not days_unconstrained:
        return None

    minute, hour = schedule.minute, schedule.hour

    if minute.is_wildcard and hour.is_wildcard:
        return "Every minute"

    if minute.is_wildcard_step and hour.is_wildcard:
        return f"Every {minute.step} minutes"

    if _is_zero(minute) and hour.is_wildcard_step:
        return f"Every {hour.step} hours, on the hour"

    return None


def _describe_time(minute: FieldSchedule, hour: FieldSchedule) -> str:
    """Describe the time-of-day portion of the schedule."""
    if minute.is_single_value and hour.is_single_value:
        h, m = hour.values[0], minute.values[0]
        if h == 0 and m == 0:
            return "At midnight"
        return f"At {h:02d}:{m:02d}"

    if minute.is_single_value and hour.is_wildcard:
        return f"At minute {minute.values[0]} of every hour"

    minutes = _describe_numbers(minute.values)
    hours = _describe_numbers(hour.values)
    return f"At minute(s) {minutes} of hour(s) {hours}"


def _describe_days(
    day_of_month: FieldSchedule, month: FieldSchedule, day_of_week: FieldSchedule
) -> str:
    """Describe day-of-week, day-of-month, and month constraints, if any."""
    clauses: list[str] = []

    if not day_of_week.is_wildcard:
        weekdays = [WEEKDAY_NAMES[value] for value in day_of_week.values]
        clauses.append("on " + _describe_names(weekdays, day_of_week.values))

    if not day_of_month.is_wildcard:
        days = _join_human([_ordinal(value) for value in day_of_month.values])
        clauses.append(f"on the {days} of every month")

    if not month.is_wildcard:
        months = [MONTH_NAMES[value - 1] for value in month.values]
        clauses.append("in " + _describe_names(months, month.values))

    return " and ".join(clauses)


# --------------------------------------------------------------------------- #
# Small description helpers
# --------------------------------------------------------------------------- #


def _describe_names(names: list[str], values: tuple[int, ...]) -> str:
    """Render named values, collapsing a contiguous run into "A through Z"."""
    if len(values) > 2 and _is_contiguous(values):
        return f"{names[0]} through {names[-1]}"
    return _join_human(names)


def _describe_numbers(values: tuple[int, ...]) -> str:
    """Render numeric values, collapsing a contiguous run into "A through Z"."""
    text = [str(value) for value in values]
    if len(values) > 2 and _is_contiguous(values):
        return f"{text[0]} through {text[-1]}"
    return _join_human(text)


def _join_human(items: list[str]) -> str:
    """Join items as natural English: "A", "A and B", or "A, B, and C"."""
    if len(items) == 1:
        return items[0]
    if len(items) == 2:
        return f"{items[0]} and {items[1]}"
    return ", ".join(items[:-1]) + ", and " + items[-1]


def _is_contiguous(values: tuple[int, ...]) -> bool:
    """True if `values` form an unbroken ascending run (e.g. 1, 2, 3, 4, 5)."""
    return all(later - earlier == 1 for earlier, later in zip(values, values[1:]))


def _is_zero(field: FieldSchedule) -> bool:
    """True if a field matches exactly the single value 0."""
    return field.values == (0,)


def _ordinal(number: int) -> str:
    """Format an integer as an ordinal string: 1 -> "1st", 22 -> "22nd"."""
    if 10 <= number % 100 <= 20:
        suffix = "th"
    else:
        suffix = {1: "st", 2: "nd", 3: "rd"}.get(number % 10, "th")
    return f"{number}{suffix}"


# --------------------------------------------------------------------------- #
# Demo
# --------------------------------------------------------------------------- #

if __name__ == "__main__":
    examples = [
        "* * * * *",
        "0 12 * * 1-5",
        "*/15 * * * *",
        "0 0 1 * *",
        "30 8 * * 1,3,5",
        "0 */2 * * *",
    ]
    for expression in examples:
        print(f"{expression:18} -> {parse_cron(expression).describe()}")
```

Running it produces exactly the target descriptions:

