from __future__ import annotations

from dataclasses import dataclass


@dataclass(frozen=True)
class FieldSpec:
    name: str
    minimum: int
    maximum: int


@dataclass(frozen=True)
class FieldPart:
    raw: str
    start: int
    end: int
    step: int
    values: tuple[int, ...]

    @property
    def is_wildcard(self) -> bool:
        return self.start == self.end == -1


@dataclass(frozen=True)
class ParsedField:
    spec: FieldSpec
    raw: str
    parts: tuple[FieldPart, ...]
    values: tuple[int, ...]

    def is_any(self) -> bool:
        return self.raw == "*"

    def is_single_value(self) -> bool:
        return len(self.values) == 1 and self.raw.isdigit()

    def single_value(self) -> int:
        if not self.is_single_value():
            raise ValueError(f"{self.spec.name} is not a single value")
        return self.values[0]


@dataclass(frozen=True)
class CronSchedule:
    minute: ParsedField
    hour: ParsedField
    day_of_month: ParsedField
    month: ParsedField
    day_of_week: ParsedField

    def describe(self) -> str:
        minute = self.minute
        hour = self.hour
        dom = self.day_of_month
        month = self.month
        dow = self.day_of_week

        if all(field.is_any() for field in [minute, hour, dom, month, dow]):
            return "Every minute"

        if (
            minute.raw.startswith("*/")
            and hour.is_any()
            and dom.is_any()
            and month.is_any()
            and dow.is_any()
        ):
            return f"Every {minute.parts[0].step} minutes"

        if (
            minute.single_value_or_none() == 0
            and hour.raw.startswith("*/")
            and dom.is_any()
            and month.is_any()
            and dow.is_any()
        ):
            return f"Every {hour.parts[0].step} hours, on the hour"

        description = describe_time(minute, hour)

        date_parts: list[str] = []

        if not dom.is_any():
            date_parts.append(describe_day_of_month(dom))

        if not month.is_any():
            date_parts.append(describe_month(month))

        if not dow.is_any():
            date_parts.append(describe_day_of_week(dow))

        if date_parts:
            description += " " + " ".join(date_parts)

        return description


def parse_cron(expression: str) -> CronSchedule:
    fields = expression.split()

    if len(fields) != 5:
        raise ValueError(
            "Cron expression must contain exactly 5 fields: "
            "minute hour day_of_month month day_of_week"
        )

    minute, hour, day_of_month, month, day_of_week = fields

    return CronSchedule(
        minute=parse_field(minute, FieldSpec("minute", 0, 59)),
        hour=parse_field(hour, FieldSpec("hour", 0, 23)),
        day_of_month=parse_field(day_of_month, FieldSpec("day_of_month", 1, 31)),
        month=parse_field(month, FieldSpec("month", 1, 12)),
        day_of_week=parse_field(day_of_week, FieldSpec("day_of_week", 0, 6)),
    )


def parse_field(raw: str, spec: FieldSpec) -> ParsedField:
    if not raw:
        raise ValueError(f"{spec.name} field cannot be empty")

    parts = tuple(parse_field_part(part, spec) for part in raw.split(","))
    values = tuple(sorted({value for part in parts for value in part.values}))

    if not values:
        raise ValueError(f"{spec.name} field produced no valid values: {raw!r}")

    return ParsedField(spec=spec, raw=raw, parts=parts, values=values)


def parse_field_part(raw: str, spec: FieldSpec) -> FieldPart:
    if not raw:
        raise ValueError(f"{spec.name} contains an empty list item")

    base, step = split_step(raw, spec)
    start, end = parse_base(base, spec)

    if step <= 0:
        raise ValueError(f"{spec.name} step must be greater than 0: {raw!r}")

    if base == "*":
        values = tuple(range(spec.minimum, spec.maximum + 1, step))
        return FieldPart(raw=raw, start=-1, end=-1, step=step, values=values)

    values = tuple(range(start, end + 1, step))
    return FieldPart(raw=raw, start=start, end=end, step=step, values=values)


def split_step(raw: str, spec: FieldSpec) -> tuple[str, int]:
    if "/" not in raw:
        return raw, 1

    pieces = raw.split("/")
    if len(pieces) != 2 or not pieces[0] or not pieces[1]:
        raise ValueError(f"Invalid step syntax in {spec.name}: {raw!r}")

    base, step_text = pieces

    if not step_text.isdigit():
        raise ValueError(f"{spec.name} step must be a number: {raw!r}")

    return base, int(step_text)


def parse_base(base: str, spec: FieldSpec) -> tuple[int, int]:
    if base == "*":
        return spec.minimum, spec.maximum

    if "-" in base:
        return parse_range(base, spec)

    value = parse_int(base, spec)
    ensure_in_range(value, spec)
    return value, value


def parse_range(raw: str, spec: FieldSpec) -> tuple[int, int]:
    pieces = raw.split("-")

    if len(pieces) != 2 or not pieces[0] or not pieces[1]:
        raise ValueError(f"Invalid range syntax in {spec.name}: {raw!r}")

    start = parse_int(pieces[0], spec)
    end = parse_int(pieces[1], spec)

    ensure_in_range(start, spec)
    ensure_in_range(end, spec)

    if start > end:
        raise ValueError(f"{spec.name} range start cannot exceed end: {raw!r}")

    return start, end


def parse_int(text: str, spec: FieldSpec) -> int:
    if not text.isdigit():
        raise ValueError(f"{spec.name} value must be a number: {text!r}")

    return int(text)


def ensure_in_range(value: int, spec: FieldSpec) -> None:
    if not spec.minimum <= value <= spec.maximum:
        raise ValueError(
            f"{spec.name} value {value} is outside allowed range "
            f"{spec.minimum}-{spec.maximum}"
        )


def describe_time(minute: ParsedField, hour: ParsedField) -> str:
    if minute.is_single_value() and hour.is_single_value():
        hour_value = hour.single_value()
        minute_value = minute.single_value()

        if hour_value == 0 and minute_value == 0:
            return "At midnight"

        return f"At {hour_value:02d}:{minute_value:02d}"

    if minute.is_single_value() and minute.single_value() == 0:
        return "Every hour, on the hour"

    if hour.is_any():
        return describe_minute_pattern(minute)

    return f"At {describe_field_values(hour)} hours and {describe_field_values(minute)} minutes"


def describe_minute_pattern(minute: ParsedField) -> str:
    if minute.raw.startswith("*/"):
        return f"Every {minute.parts[0].step} minutes"

    if minute.is_single_value():
        return f"At minute {minute.single_value()} of every hour"

    return f"At minutes {describe_field_values(minute)}"


def describe_day_of_month(field: ParsedField) -> str:
    if field.is_single_value():
        return f"on the {ordinal(field.single_value())} of every month"

    return f"on days {describe_field_values(field)} of every month"


def describe_month(field: ParsedField) -> str:
    return f"in {describe_named_values(field, MONTH_NAMES)}"


def describe_day_of_week(field: ParsedField) -> str:
    return f"on {describe_named_values(field, DAY_NAMES)}"


def describe_field_values(field: ParsedField) -> str:
    return join_english([str(value) for value in field.values])


def describe_named_values(field: ParsedField, names: dict[int, str]) -> str:
    if len(field.parts) == 1:
        part = field.parts[0]
        if part.step == 1 and part.start != -1 and part.start != part.end:
            return f"{names[part.start]} through {names[part.end]}"

    return join_english([names[value] for value in field.values])


def join_english(items: list[str]) -> str:
    if len(items) == 1:
        return items[0]

    if len(items) == 2:
        return f"{items[0]} and {items[1]}"

    return f"{', '.join(items[:-1])}, and {items[-1]}"


def ordinal(value: int) -> str:
    if 10 <= value % 100 <= 20:
        suffix = "th"
    else:
        suffix = {1: "st", 2: "nd", 3: "rd"}.get(value % 10, "th")

    return f"{value}{suffix}"


def single_value_or_none(field: ParsedField) -> int | None:
    return field.single_value() if field.is_single_value() else None


ParsedField.single_value_or_none = single_value_or_none  # optional convenience


MONTH_NAMES = {
    1: "January",
    2: "February",
    3: "March",
    4: "April",
    5: "May",
    6: "June",
    7: "July",
    8: "August",
    9: "September",
    10: "October",
    11: "November",
    12: "December",
}

DAY_NAMES = {
    0: "Sunday",
    1: "Monday",
    2: "Tuesday",
    3: "Wednesday",
    4: "Thursday",
    5: "Friday",
    6: "Saturday",
}
